mapper.select:
/* usimDlvryMgmtMapper.getUsimDirDlvryList */
SELECT A.SELF_DLVRY_IDX ,A.KT_ORD_ID ,A.BIZ_ORG_CD ,FN_GET_CODENM('RCP9025' , BIZ_ORG_CD ) AS BIZ_ORG_NM ,A.DELIVERY_ORDER_ID ,A.USIM_AMT ,A.CSTMR_NAME ,A.DLVRY_TEL_FN ,A.DLVRY_TEL_MN ,A.DLVRY_TEL_RN ,(A.DLVRY_TEL_FN || A.DLVRY_TEL_MN || A.DLVRY_TEL_RN ) AS DLVRY_TEL ,A.DLVRY_NAME ,A.DLVRY_POST ,A.DLVRY_ADDR ,A.DLVRY_ADDR_DTL ,A.DLVRY_MEMO ,A.SELF_MEMO ,A.DLVRY_STATE_CODE ,FN_GET_CODENM('RCP9024' , A.DLVRY_STATE_CODE ) AS DLVRY_STATE_NM ,A.SELF_STATE_CODE ,FN_GET_CODENM('RCP9026' , A.SELF_STATE_CODE ) AS SELF_STATE_NM ,A.SVC_RSLT_CD ,FN_GET_CODENM('RCP9028' , A.SVC_RSLT_CD ) AS SVC_RSLT ,A.SVC_RSLT_MSG ,A.PAY_CD , FN_GET_CODENM('RCP9027' , A.PAY_CD ) AS PAY_STATE , A.REQ_TYPE , DECODE(A.REQ_TYPE , '02' , '온라인신청서' , '유심구매') AS REQ_TYPE_NM , NVL(A.MINOR_AGENT_NAME, C.MINOR_AGENT_NAME) AS MINOR_AGENT_NAME , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = A.RVISN_ID) AS RVISN_NM , A.RVISN_ID ,TO_CHAR(A.SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_RDATE ,A.SYS_RDATE AS SYS_TIME ,TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS' ) AS RVISN_DTTM ,DECODE(A.DLVRY_STATE_CODE , '04' , (SELECT MAX(TO_CHAR(REGST_DTTM , 'YYYY-MM-DD HH24:MI:SS' )) FROM MSP_DIRDVRY_USIM_HST WHERE KT_ORD_ID = A.KT_ORD_ID AND DLVRY_STATE_CODE = '04') )AS CPL_DATE , A.ACCEPT_TIME , A.ORDER_STAT_RSN_DESC , B.RES_NO , FN_GET_CODENM('RCP9025', A.RE_BIZ_ORG_CD) AS RE_BIZ_ORG_NM , A.RE_ACCEPT_YN , DECODE( (SELECT DISTINCT CNCL_RST_CD FROM NMCP_DAOUPAY_INFO@DL_MCP WHERE ORDERNO = TO_CHAR(A.SELF_DLVRY_IDX)) , '01', '성공', '02', '오류', '') AS CNCL_YN_STAT -- 결제취소 상태 , (SELECT DISTINCT CNCL_FAIL_RSN FROM NMCP_DAOUPAY_INFO@DL_MCP WHERE ORDERNO = TO_CHAR(A.SELF_DLVRY_IDX)) AS CNCL_FAIL_RSN -- 결제취소 실패사유 , (SELECT DISTINCT ADM.ADMIN_NM FROM NMCP_ADMIN_MEMBER_BAS@DL_MCP ADM , NMCP_DAOUPAY_INFO@DL_MCP DAU WHERE DAU.CNCL_ID = ADM.ADMIN_ID AND DAU.ORDERNO = TO_CHAR(A.SELF_DLVRY_IDX)) AS CNCL_NM -- 결제취소 처리자 , (SELECT DISTINCT TO_CHAR(CNCL_DT, 'YYYY-MM-DD HH24:MI:SS') FROM NMCP_DAOUPAY_INFO@DL_MCP WHERE TO_CHAR(A.SELF_DLVRY_IDX) = ORDERNO) AS CNCL_DT -- 결제취소 처리일시 , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'usimProdInfo' AND DTL_CD = USIM_PROD_ID) AS USIM_PROD_NM -- 유심종류 FROM MCP_REQUEST_NOW_DLVRY@DL_MCP A , MCP_REQUEST@DL_MCP B , MCP_REQUEST_AGENT@DL_MCP C WHERE A.REQUEST_KEY = B.REQUEST_KEY(+) AND A.REQUEST_KEY = C.REQUEST_KEY(+) AND A.CHANNEL_CD IS NULL
AND TO_CHAR(A.SYS_RDATE, 'YYYYMMDD') BETWEEN #{strtDt} AND #{endDt}
AND A.DLVRY_STATE_CODE = #{dvryStatCd}
AND A.SELF_STATE_CODE = #{selfStateCode}
AND A.SVC_RSLT_CD = #{svcRsltCd}
AND A.PAY_CD = #{payCd}
AND A.CSTMR_NAME like '%' || #{searchVal} || '%'
AND (A.DLVRY_TEL_FN || A.DLVRY_TEL_MN || A.DLVRY_TEL_RN ) = #{searchVal}
AND A.BIZ_ORG_CD = ( SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9025' AND CD_DSC like '%' || #{searchVal} || '%')
AND A.SELF_DLVRY_IDX = #{searchVal}
AND A.KT_ORD_ID = #{searchVal}
AND B.RES_NO = #{searchVal}
ORDER BY SYS_TIME DESC

/* usimDlvryMgmtMapper.getUsimDlvryListByExcel */ SELECT TO_CHAR(A.SELF_DLVRY_IDX) AS SELF_DLVRY_IDX ,A.KT_ORD_ID ,A.BIZ_ORG_CD ,FN_GET_CODENM('RCP9025' , A.BIZ_ORG_CD ) AS BIZ_ORG_NM ,A.DELIVERY_ORDER_ID ,A.USIM_AMT ,A.CSTMR_NAME ,A.DLVRY_TEL_FN ,A.DLVRY_TEL_MN ,A.DLVRY_TEL_RN ,(A.DLVRY_TEL_FN || A.DLVRY_TEL_MN || A.DLVRY_TEL_RN ) AS DLVRY_TEL , A.DLVRY_NAME ,A.DLVRY_POST ,A.DLVRY_ADDR ,A.DLVRY_ADDR_DTL ,(A.DLVRY_ADDR || ' ' || A.DLVRY_ADDR_DTL) AS DLVRY_POST_ADDR ,A.DLVRY_MEMO ,A.SELF_MEMO ,A.DLVRY_STATE_CODE ,FN_GET_CODENM('RCP9024' , A.DLVRY_STATE_CODE ) AS DLVRY_STATE_NM ,A.SELF_STATE_CODE ,FN_GET_CODENM('RCP9026' , A.SELF_STATE_CODE ) AS SELF_STATE_NM ,A.SVC_RSLT_CD ,FN_GET_CODENM('RCP9028' , A.SVC_RSLT_CD ) AS SVC_RSLT ,A.SVC_RSLT_MSG ,A.PAY_CD , FN_GET_CODENM('RCP9027' , A.PAY_CD ) AS PAY_STATE , A.REQ_TYPE , DECODE(A.REQ_TYPE , '02' , '온라인신청서' , '유심구매') AS REQ_TYPE_NM , NVL(A.MINOR_AGENT_NAME, C.MINOR_AGENT_NAME) AS MINOR_AGENT_NAME , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = A.RVISN_ID) AS RVISN_NM ,A.RVISN_ID ,TO_CHAR(A.SYS_RDATE, 'YYYY-MM-DD HH24:MI:SS' ) AS SYS_RDATE ,A.SYS_RDATE AS SYS_TIME ,TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS' ) AS RVISN_DTTM , DECODE(A.DLVRY_STATE_CODE , '04' , (SELECT MAX(TO_CHAR(REGST_DTTM , 'YYYY-MM-DD HH24:MI:SS' )) FROM MSP_DIRDVRY_USIM_HST WHERE KT_ORD_ID = A.KT_ORD_ID AND DLVRY_STATE_CODE = '04') )AS CPL_DATE , A.ACCEPT_TIME , A.ORDER_STAT_RSN_DESC , B.RES_NO , FN_GET_CODENM('RCP9025' , A.RE_BIZ_ORG_CD ) AS RE_BIZ_ORG_NM , A.RE_ACCEPT_YN , DECODE( (SELECT DISTINCT CNCL_RST_CD FROM NMCP_DAOUPAY_INFO@DL_MCP WHERE ORDERNO = TO_CHAR(A.SELF_DLVRY_IDX)) , '01', '성공', '02', '오류', '') AS CNCL_YN_STAT -- 결제취소 상태 , (SELECT DISTINCT CNCL_FAIL_RSN FROM NMCP_DAOUPAY_INFO@DL_MCP WHERE ORDERNO = TO_CHAR(A.SELF_DLVRY_IDX)) AS CNCL_FAIL_RSN -- 결제취소 실패사유 , (SELECT DISTINCT ADM.ADMIN_NM FROM NMCP_ADMIN_MEMBER_BAS@DL_MCP ADM , NMCP_DAOUPAY_INFO@DL_MCP DAU WHERE DAU.CNCL_ID = ADM.ADMIN_ID AND DAU.ORDERNO = TO_CHAR(A.SELF_DLVRY_IDX)) AS CNCL_NM -- 결제취소 처리자 , (SELECT DISTINCT TO_CHAR(CNCL_DT, 'YYYY-MM-DD HH24:MI:SS') FROM NMCP_DAOUPAY_INFO@DL_MCP WHERE TO_CHAR(A.SELF_DLVRY_IDX) = ORDERNO) AS CNCL_DT -- 결제취소 처리일시 , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'usimProdInfo' AND DTL_CD = USIM_PROD_ID) AS USIM_PROD_NM -- 유심종류 FROM MCP_REQUEST_NOW_DLVRY@DL_MCP A , MCP_REQUEST@DL_MCP B , MCP_REQUEST_AGENT@DL_MCP C WHERE A.REQUEST_KEY = B.REQUEST_KEY(+) AND A.REQUEST_KEY = C.REQUEST_KEY(+) AND A.CHANNEL_CD IS NULL
AND TO_CHAR(A.SYS_RDATE, 'YYYYMMDD') BETWEEN #{strtDt} AND #{endDt}
AND A.DLVRY_STATE_CODE = #{dvryStatCd}
AND A.SELF_STATE_CODE = #{selfStateCode}
AND A.SVC_RSLT_CD = #{svcRsltCd}
AND A.PAY_CD = #{payCd}
AND A.CSTMR_NAME like '%' || #{searchVal} || '%'
AND (A.DLVRY_TEL_FN || A.DLVRY_TEL_MN || A.DLVRY_TEL_RN ) = #{searchVal}
AND A.BIZ_ORG_CD = ( SELECT CD_VAL FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP9025' AND CD_DSC like '%' || #{searchVal} || '%')
AND A.SELF_DLVRY_IDX = #{searchVal}
AND A.KT_ORD_ID = #{searchVal}
AND B.RES_NO = #{searchVal}
ORDER BY SYS_TIME DESC

mapper.update:
/* usimDlvryMgmtMapper.updateUsimDirDlvryInfo */
UPDATE	MCP_REQUEST_NOW_DLVRY@DL_MCP
SET	  PAY_CD = #{payCd, jdbcType=VARCHAR}
        , SELF_MEMO   = #{selfMemo, jdbcType=VARCHAR}
        , RVISN_ID          = #{sessionUserId, jdbcType=VARCHAR}
        , RVISN_DTTM        = SYSDATE
WHERE	SELF_DLVRY_IDX      = #{selfDlvryIdx, jdbcType=VARCHAR}

/* usimDlvryMgmtMapper.updateUsimDirDlvryStateCd */
UPDATE	MCP_REQUEST_NOW_DLVRY@DL_MCP
SET	  SELF_STATE_CODE = #{selfStateCode, jdbcType=VARCHAR}
        , RVISN_ID          = #{sessionUserId, jdbcType=VARCHAR}
        , RVISN_DTTM        = SYSDATE
WHERE	SELF_DLVRY_IDX      = #{selfDlvryIdx, jdbcType=VARCHAR}

mapper.select:
/* usimDlvryMgmtMapper.chkUsimDirDlvryHst */
SELECT	COUNT(*) AS CNT
FROM    MSP_REQUEST_NOW_DLVRY_HST A
WHERE   SELF_DLVRY_IDX = #{selfDlvryIdx, jdbcType=VARCHAR}

mapper.insert:
/* usimDlvryMgmtMapper.updateUsimDirDlvryHst */ INSERT INTO MSP_REQUEST_NOW_DLVRY_HST ( NOW_DLVRY_HST_SEQ , SELF_DLVRY_IDX , SELF_MEMO , ORDER_STAT_RSN_DESC , DLVRY_STATE_CODE , SELF_STATE_CODE , PAY_CD , RVISN_ID , RVISN_DTTM ) SELECT SQ_NOW_DLVRY_HST_SEQ.NEXTVAL , SELF_DLVRY_IDX
, #{selfMemo, jdbcType=VARCHAR}
, SELF_MEMO
, ORDER_STAT_RSN_DESC , DLVRY_STATE_CODE , SELF_STATE_CODE
, #{payCd, jdbcType=VARCHAR}
, PAY_CD
, #{sessionUserId, jdbcType=VARCHAR} , SYSDATE FROM MCP_REQUEST_NOW_DLVRY@DL_MCP WHERE SELF_DLVRY_IDX = #{selfDlvryIdx, jdbcType=VARCHAR}
